{
  "competency_groups": [
    {
      "code": "C1",
      "title": "Conceptual Foundations and Measurement",
      "description": "Equip learners with tools to understand the working of Chemistry, develop conceptual foundations, represent phenomena at macroscopic/molecular/symbolic levels, identify patterns, and apply knowledge to real-life situations.",
      "competencies": [
        "Understand nature of matter, properties, measurement, uncertainty, laws of chemical combination, Dalton's atomic theory",
        "Calculate atomic/molecular masses, mole concept, molar mass, percentage composition, stoichiometry"
      ],
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry"
    },
    {
      "code": "C2",
      "title": "Atomic Structure and Quantum Mechanics",
      "description": "Enable learners to trace the development from sub-atomic particles discovery through Bohr's model to the quantum mechanical model.",
      "competencies": [
        "Explain discovery of sub-atomic particles, atomic models, developments leading to Bohr's model"
      ],
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom"
    },
    {
      "code": "C3",
      "title": "Periodic Classification and Trends",
      "description": "Enable learners to classify elements, understand periodic law, electronic configurations, block types, and trends in properties.",
      "competencies": [
        "Explain genesis of periodic classification, modern periodic law, nomenclature for Z>100"
      ],
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties"
    },
    {
      "code": "C4",
      "title": "Chemical Bonding Theories",
      "description": "Enable learners to apply various bonding theories (Kossel-Lewis, VSEPR, Valence Bond, Molecular Orbital) and understand hybridization.",
      "competencies": [
        "Apply Kossel-Lewis approach, Ionic/Electrovalent bond concepts"
      ],
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure"
    },
    {
      "code": "C5",
      "title": "Thermodynamics and Spontaneity",
      "description": "Enable learners to analyze thermodynamic terms, enthalpy changes, calorimetry, spontaneity, Gibbs energy change, and equilibrium.",
      "competencies": [
        "Analyze applications of thermodynamics, measurement of ∆U and ∆H"
      ],
      "unit_name": "Thermodynamics",
      "chapter_name": "Chemical Thermodynamics"
    },
    {
      "code": "C6",
      "title": "Equilibrium Principles",
      "description": "Enable learners to understand dynamic equilibrium, constants (K), reaction quotient (Q), Gibbs energy relationship, and factors affecting equilibria.",
      "competencies": [
        "Analyze homogeneous/heterogeneous equilibria, ionic equilibrium in solution"
      ],
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium"
    },
    {
      "code": "C7",
      "title": "Redox and Electrode Processes",
      "description": "Enable learners to identify oxidation/reduction in terms of electron transfer, assign oxidation numbers, and relate redox to electrode processes.",
      "competencies": [
        "Classify classical ideas vs. electron transfer concepts"
      ],
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions"
    },
    {
      "code": "C8",
      "title": "Organic Chemistry Fundamentals and Mechanisms",
      "description": "Enable learners to represent organic compounds, classify them, apply IUPAC nomenclature, understand isomerism, reaction mechanisms, and purification techniques.",
      "competencies": [
        "Apply structural representations, classification, nomenclature"
      ],
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Some basic Principles and Techniques"
    },
    {
      "code": "C9",
      "title": "Hydrocarbon Classification and Properties",
      "description": "Enable learners to classify hydrocarbons, understand properties of alkanes, alkenes, alkynes, aromatic compounds, and assess carcinogenic/toxicity.",
      "competencies": [
        "Classify and analyze properties of Alkanes, Alkenes, Alkynes"
      ],
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons"
    },
    {
      "code": "C10",
      "title": "Solution Chemistry and Colligative Properties",
      "description": "Enable learners to express concentration, understand solubility, vapor pressure, ideal/non-ideal solutions, and determine molar mass via colligative properties.",
      "competencies": [
        "Apply concepts of types of solutions, expression of concentration"
      ],
      "unit_name": "Unit 1",
      "chapter_name": "Solutions"
    },
    {
      "code": "C11",
      "title": "Electrochemistry and Energy Conversion",
      "description": "Enable learners to understand electrochemical cells, galvanic cells, Nernst equation, conductance, electrolytic cells, batteries, fuel cells, and corrosion.",
      "competencies": [
        "Analyze operation of Galvanic Cells and Electrolytic Cells"
      ],
      "unit_name": "Unit 2",
      "chapter_name": "Electrochemistry"
    },
    {
      "code": "C12",
      "title": "Chemical Kinetics and Reaction Rates",
      "description": "Enable learners to analyze rate of reaction, factors influencing it, integrated rate equations, temperature dependence, and collision theory.",
      "competencies": [
        "Apply concepts of rate determination and temperature effects"
      ],
      "unit_name": "Unit 3",
      "chapter_name": "Chemical Kinetics"
    },
    {
      "code": "C13",
      "title": "d-and f-Block Elements Chemistry",
      "description": "Enable learners to understand position in periodic table, electronic configuration of d-block elements, general properties, important compounds, lanthanoids, actinoids.",
      "competencies": [
        "Analyze general properties and applications of Transition Elements"
      ],
      "unit_name": "Unit 4",
      "chapter_name": "d-and f-Block Elements"
    },
    {
      "code": "C14",
      "title": "Coordination Compounds Theory",
      "description": "Enable learners to apply Werner's theory, understand nomenclature, isomerism, bonding (including metal carbonyls), and applications.",
      "competencies": [
        "Apply definitions of terms pertaining to Coordination Compounds"
      ],
      "unit_name": "Unit 5",
      "chapter_name": "Coordination Compounds"
    },
    {
      "code": "C15",
      "title": "Haloalkanes and Haloarenes Chemistry",
      "description": "Enable learners to classify, name, understand C-X bond nature, preparation methods (haloalkanes/haloarenes), physical properties, chemical reactions.",
      "competencies": [
        "Analyze classification and nomenclature of halo compounds"
      ],
      "unit_name": "Unit 6",
      "chapter_name": "Haloalkanes and Haloarenes"
    },
    {
      "code": "C16",
      "title": "Alcohols, Phenols and Ethers Chemistry",
      "description": "Enable learners to classify compounds, apply nomenclature rules, understand structures of functional groups, and properties.",
      "competencies": [
        "Differentiate between Alcohols, Phenols, and Ethers"
      ],
      "unit_name": "Unit 7",
      "chapter_name": "Alcohols, Phenols and Ethers"
    },
    {
      "code": "C17",
      "title": "Carbonyl Compounds Chemistry",
      "description": "Enable learners to understand nomenclature/structure of carbonyl/carboxyl groups, preparation methods, physical properties, chemical reactions.",
      "competencies": [
        "Analyze Preparation and Uses of Aldehydes/Ketones"
      ],
      "unit_name": "Unit 8",
      "chapter_name": "Aldehydes, Ketones and Carboxylic Acids"
    },
    {
      "code": "C18",
      "title": "Amines Chemistry",
      "description": "Enable learners to understand structure, classification, nomenclature, preparation methods (including Diazonium salts), physical properties.",
      "competencies": [
        "Analyze Chemical Reactions and Importance of Diazonium Salts"
      ],
      "unit_name": "Unit 9",
      "chapter_name": "Amines"
    },
    {
      "code": "C19",
      "title": "Biomolecules Chemistry",
      "description": "Enable learners to identify and understand the structure and function of carbohydrates, proteins, enzymes, vitamins, nucleic acids, hormones.",
      "competencies": [
        "Identify components of Biomolecules"
      ],
      "unit_name": "Unit 10",
      "chapter_name": "Biomolecules"
    },
    {
      "code": "C20",
      "title": "Problem Solving and Scientific Inquiry",
      "description": "Inculcate problem-solving skills, integrate life skills/values in context of chemistry, contribute to frontier research areas (climate change, environment), interface with other disciplines.",
      "competencies": [
        "Apply acquired knowledge to solve problems in new situations"
      ],
      "unit_name": "",
      "chapter_name": ""
    }
  ]
}
